    t: 0, hull: 3, cargo: 0, inv: 2, wins: 0, runT: 0, bestT: 0, winGlow: 0,
    head: -1.57, trim: 0.5, vx: 0, vy: 0,
    windA: 0.6, windV: 6.0, over: 0, boom: 0.4, heel: 0,
    deliverGlow: 0, place: 1
  }
  const G = wd.__tr
