  G.dayT = (G.dayT + dt / 300) % 1
  if (wd.__forceDay !== undefined) { G.dayT = wd.__forceDay; delete wd.__forceDay }
  const el = Math.sin(G.dayT * 6.2832) * 0.55 + 0.18
  const sunAz = G.dayT * 6.2832 - 1.5708
