    const eff = smoothstep(0.30, 0.72, offA) * (0.6 + 0.4 * Math.sin(Math.min(offA, 2.0)))
    const idealTrim = Math.min(1, Math.max(0.15, offA / Math.PI))
    G.trim += (idealTrim - G.trim) * 0.22 * dt
