        if (p) {
          T(p).x = Math.max(40, Math.min(472, T(boat).x - fwd[0] * 30))
          T(p).y = Math.max(40, Math.min(472, T(boat).y - fwd[1] * 30))
          p.visualParams = [Math.random(), 0, 0, 0]
        }
      }
    }

    // ── integrate ──
    G.vx += fwd[0] * drive * dt; G.vy += fwd[1] * drive * dt
    G.vx += -fwd[1] * G.heel * 3.5 * dt; G.vy += fwd[0] * G.heel * 3.5 * dt
    G.vx += wdx * 1.4 * dt; G.vy += wdy * 1.4 * dt
    if (whirl) {
      const mx = T(whirl).x - T(boat).x, my = T(whirl).y - T(boat).y
      const md = Math.hypot(mx, my) || 1
      if (md < 165) {
        const pull = 5200 / (md * md)
        G.vx += (mx / md) * pull; G.vy += (my / md) * pull
        G.vx += (-my / md) * pull * 0.55; G.vy += (mx / md) * pull * 0.55
        if (md < 26 && G.inv <= 0) { hullHit(mx, my, md, 1) }
      }
      whirl.visualParams = [1, 0, 0, 0]
    }
    // the keel grips: sideways slip dies fast, the boat goes where it points
    let vF = G.vx * fwd[0] + G.vy * fwd[1]
    let vL = -G.vx * fwd[1] + G.vy * fwd[0]
    vF -= vF * Math.min(0.9, (1.15 + G.cargo * 0.06) * dt)
    vL -= vL * Math.min(0.95, 2.8 * dt)
    G.vx = fwd[0] * vF - fwd[1] * vL
    G.vy = fwd[1] * vF + fwd[0] * vL
    const spd = Math.hypot(G.vx, G.vy)
    const cap2 = 46 + 12 * (gust - 1)
    if (spd > cap2) { G.vx *= cap2 / spd; G.vy *= cap2 / spd }
    T(boat).x += G.vx * dt; T(boat).y += G.vy * dt
    T(boat).x = Math.max(14, Math.min(498, T(boat).x))
    T(boat).y = Math.max(14, Math.min(498, T(boat).y))
    T(boat).vx = 0; T(boat).vy = 0

    // ── rocks: hard contact; three hits and the sea takes the pearls back ──
    function hullHit(nx, ny, nd, soft) {
      G.hull--; G.inv = 2.2
      G.vx -= (nx / nd) * (soft ? 60 : 85); G.vy -= (ny / nd) * (soft ? 60 : 85)
      if (G.hull <= 0) {
        G.hull = 3; G.cargo = 0; G.place = 1
        T(boat).x = 412; T(boat).y = 205; G.vx = 0; G.vy = 0; G.head = 1.9; G.trim = 0.3; G.inv = 3
      }
    }
    for (const rk of rocks) {
      const rr = (rk.properties.get('rr') || 26)
      const rx = T(boat).x - T(rk).x, ry = T(boat).y - T(rk).y
      const rd2 = Math.hypot(rx, ry) || 1
      if (rd2 < rr && G.inv <= 0) {
        hullHit(-rx, -ry, rd2, 0)
        const vn = (G.vx * rx + G.vy * ry) / rd2
        if (vn < 0) { G.vx -= 1.6 * vn * rx / rd2; G.vy -= 1.6 * vn * ry / rd2 }
      }
      T(rk).vx = 0; T(rk).vy = 0
    }
    if (light) {
      const lx = T(boat).x - T(light).x, ly = T(boat).y - T(light).y
      const ld = Math.hypot(lx, ly) || 1
      if (ld < 34 && G.inv <= 0) hullHit(-lx, -ly, ld, 0)
      light.visualParams = [G.t * 0.55, Math.max(G.deliverGlow, G.winGlow / 3), 0, 0]
      T(light).vx = 0; T(light).vy = 0
    }

    // ── the pearls: scatter on a fresh run, bob in place, NEVER leave the grid ──
    if (G.place) {
      G.place = 0
      const placed = []
      for (const p of pearls) {
        let x = 0, y = 0, ok = false, tries = 0
        while (!ok && tries < 20) {
          tries++
          x = 60 + Math.random() * 392; y = 60 + Math.random() * 392
          ok = true
          for (const rk of rocks) if (Math.hypot(x - T(rk).x, y - T(rk).y) < 65) ok = false
          if (light && Math.hypot(x - T(light).x, y - T(light).y) < 140) ok = false
          if (whirl && Math.hypot(x - T(whirl).x, y - T(whirl).y) < 55) ok = false
          for (const q of placed) if (Math.hypot(x - q[0], y - q[1]) < 110) ok = false
        }
        placed.push([x, y])
        T(p).x = x; T(p).y = y; T(p).vx = 0; T(p).vy = 0
        p.visualParams = [Math.random(), 0, 0, 0]
      }
    }
    for (const p of pearls) {
      if (!p.visualParams || p.visualParams[3] > 0.5) continue
      // gentle wind sway, hard-clamped — a pearl is a promise, it stays reachable
      T(p).x = Math.max(40, Math.min(472, T(p).x + wdx * 1.2 * dt))
      T(p).y = Math.max(40, Math.min(472, T(p).y + wdy * 1.2 * dt))
      T(p).vx = 0; T(p).vy = 0
      if (G.cargo < 3 && Math.hypot(T(boat).x - T(p).x, T(boat).y - T(p).y) < 24) {
        G.cargo++
        p.visualParams = [0, 0, 0, 1]; T(p).x = 8; T(p).y = 8
      }
    }
    // ── homecoming: all three pearls to the lighthouse dock, arrive slow ──
    if (light && G.cargo >= 3) {
      const dkx = T(light).x + 4, dky = T(light).y + 54
      if (Math.hypot(T(boat).x - dkx, T(boat).y - dky) < 34 && spd < 50) {
        G.wins++
        if (!G.bestT || G.runT < G.bestT) G.bestT = G.runT
        G.cargo = 0; G.runT = 0; G.place = 1
        G.winGlow = 4; G.deliverGlow = 1
        wd.__play_sound = { frequency: 523, duration: 0.7, volume: 0.2, type: 'sine' }
      }
    }

    // ── boom geometry & visuals ──
    const side = off > 0 ? 1 : -1
    const boomTarget = side * (0.25 + (1 - G.trim) * 0.5 + (offA / Math.PI) * 0.55)
    G.boom += (boomTarget - G.boom) * Math.min(1, dt * 5)
    boat.visualParams = [G.head, Math.min(1, spd / 50), G.boom, G.heel]
    sea.visualParams = [wdx, wdy, Math.min(1, (G.windV * gust - 4) / 6), 0]
    if (rose) {
      const warn = G.over > 0.35 || Math.abs(G.heel) > 1.0
      rose.visualParams = [off, Math.min(1, (G.windV * gust - 4) / 6), Math.min(1, drive / 90), Math.abs(G.heel) / 1.45 + (warn ? 2 : 0)]
      T(rose).x = 56; T(rose).y = 444; T(rose).vx = 0; T(rose).vy = 0
    }
    wd.gpuUniforms = [el, sunAz, G.t * 0.55, night01, Math.min(1, (G.windV * gust - 4) / 6), light ? T(light).x - 256 : 0, light ? T(light).y - 256 : 0]
    if (hud) {
      hud.visualParams = [G.hull, G.cargo, G.windA, Math.min(1, (G.windV - 4) / 5)]
      hud.name = 'TIDERUNNER \u00b7 pearls ' + G.cargo + '/3 \u00b7 ' + Math.floor(G.runT) + 's'
        + (G.bestT ? ' \u00b7 best ' + Math.floor(G.bestT) + 's' : '')
        + (G.winGlow > 0 ? ' \u00b7 THE LIGHT IS FED' : '')
        + (G.inv > 0 ? ' \u00b7 hull!' : '')
    }
  }
} catch (e) { /* keep the sim alive */ }

