        G.winGlow = 4; G.deliverGlow = 1
        wd.__play_sound = { frequency: 523, duration: 0.7, volume: 0.2, type: 'sine' }
      }
    }

    // ── boom geometry & visuals ──
    const side = off > 0 ? 1 : -1
    const boomTarget = side * (0.25 + (1 - G.trim) * 0.5 + (offA / Math.PI) * 0.55)
    G.boom += (boomTarget - G.boom) * Math.min(1, dt * 5)
    boat.visualParams = [G.head, Math.min(1, spd / 50), G.boom, G.heel]
    sea.visualParams = [wdx, wdy, Math.min(1, (G.windV * gust - 4) / 6), 0]
    if (rose) {
      const warn = G.over > 0.35 || Math.abs(G.heel) > 1.0
      rose.visualParams = [off, Math.min(1, (G.windV * gust - 4) / 6), Math.min(1, drive / 90), Math.abs(G.heel) / 1.45 + (warn ? 2 : 0)]
      T(rose).x = 56; T(rose).y = 444; T(rose).vx = 0; T(rose).vy = 0
    }
    wd.gpuUniforms = [el, sunAz, G.t * 0.55, night01, Math.min(1, (G.windV * gust - 4) / 6), light ? T(light).x - 256 : 0, light ? T(light).y - 256 : 0]
    if (hud) {
      hud.visualParams = [G.hull, G.cargo, G.windA, Math.min(1, (G.windV - 4) / 5)]
      hud.name = 'TIDERUNNER \u00b7 pearls ' + G.cargo + '/3 \u00b7 ' + Math.floor(G.runT) + 's'
        + (G.bestT ? ' \u00b7 best ' + Math.floor(G.bestT) + 's' : '')
        + (G.winGlow > 0 ? ' \u00b7 THE LIGHT IS FED' : '')
        + (G.inv > 0 ? ' \u00b7 hull!' : '')
    }
  }
} catch (e) { /* keep the sim alive */ }

visualTypes.wgsl:
fn tr_oct(uv0: vec2f, choppy: f32) -> f32 {
  let n = gnoise(uv0);
  let uv = uv0 + vec2f(n, n);
  var wv = 1.0 - abs(sin(uv));
  let swv = abs(cos(uv));
  wv = mix(wv, swv, wv);
  return pow(1.0 - pow(wv.x * wv.y, 0.65), choppy);
}
fn tr_h(pw0: vec2f, t: f32, wdir: vec2f) -> f32 {
  // FIXED world frame — the sea never rotates; the wind only pushes waves along.
  // One fixed rotation breaks the cusp lattice off the world axes (no grid).
  let p = pw0 - wdir * t * 7.0;
  var uv = (mat2x2f(0.766, 0.643, -0.643, 0.766) * p) * vec2f(0.75, 1.0);
  var freq = 0.10;
  var amp = 1.0;
  var choppy = 2.6;
  var h = 0.0;
  let st = t * 0.55;
  for (var i = 0; i < 2; i++) {
    var dd = tr_oct((uv + vec2f(st)) * freq, choppy);
    dd = dd + tr_oct((uv - vec2f(st)) * freq, choppy);
    h = h + dd * amp;
    uv = mat2x2f(1.6, 1.2, -1.2, 1.6) * uv;
    freq = freq * 1.9;
    amp = amp * 0.22;
    choppy = mix(choppy, 1.0, 0.2);
  }
  h = h + (vnoise(uv * 0.35 + vec2f(st, -st)) - 0.5) * 0.28;
  return h * 0.95 - 1.35;
}
fn visual_tr_sea(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [windX, windY, wind01, 0] · uniforms: 0 el, 1 sunAz, 2 beamA, 3 night01, 5-6 beacon xy
  var wdir = vec2f(p.x, p.y);
  if (length(wdir) < 0.1) { wdir = vec2f(1.0, 0.0); }
  wdir = normalize(wdir);
  let w01 = clamp(p.z, 0.0, 1.0);
  let pw = uv * 256.0;
  let t = time;
  let el = uni(0);
  let sunAz = uni(1);
  let night = clamp(uni(3), 0.0, 1.0);
  let day = smoothstep(-0.05, 0.30, el);
  let lowSun = smoothstep(0.35, 0.04, abs(el)) * day;
  let sun2 = vec2f(cos(sunAz), sin(sunAz));

  // choppy cusped wave field, wind-aligned (the ONE DAY octave recipe, top-down)
  let h0 = tr_h(pw, t, wdir);
  let hx = tr_h(pw + vec2f(1.7, 0.0), t, wdir);
  let hy = tr_h(pw + vec2f(0.0, 1.7), t, wdir);
  let n = normalize(vec3f((h0 - hx) * 0.55, (h0 - hy) * 0.55, 1.0));

  // water body: night indigo, day teal, crest-lightened; dawn/dusk fire on the sun side
  let deep = clamp(h0 * 0.5 + 0.5, 0.0, 1.0);
  var c = mix(vec3f(0.010, 0.016, 0.034), mix(vec3f(0.045, 0.115, 0.155), vec3f(0.065, 0.150, 0.185), deep), day);
  c = mix(c, vec3f(0.185, 0.115, 0.095), clamp(dot(uv, sun2) * 0.5 + 0.18, 0.0, 0.5) * lowSun);

  // sky reflection by slope
  let skyDay = mix(vec3f(0.20, 0.27, 0.36), vec3f(0.72, 0.40, 0.22), clamp(dot(uv, sun2) + 0.45, 0.0, 1.0) * lowSun);
  let skyRef = mix(vec3f(0.035, 0.045, 0.085), skyDay, day);
  c = mix(c, skyRef, clamp(0.20 + 0.38 * (1.0 - n.z), 0.0, 0.62));

  // sun glitter by day — gold at the horizon, whitening as it climbs
  let Ls = normalize(vec3f(sun2, 0.30 + 0.5 * max(el, 0.0)));
  let Hs = normalize(Ls + vec3f(0.0, 0.0, 1.0));
  var spg = pow(max(dot(n, Hs), 0.0), 300.0);
  spg = spg * (0.5 + 0.7 * vnoise(pw * 0.9 + vec2f(t * 0.8, -t * 0.5)));
  let sunCol = mix(vec3f(2.8, 1.5, 0.6), vec3f(2.4, 2.1, 1.6), smoothstep(0.05, 0.45, el));
  c += sunCol * spg * day * 0.55 * (0.35 + 0.65 * clamp(dot(uv, sun2) + 0.55, 0.0, 1.0));

  // moon glitter by night — silver, riding opposite the sun
  let Lm = normalize(vec3f(-sun2, 0.42));
  let Hm = normalize(Lm + vec3f(0.0, 0.0, 1.0));
  var spm = pow(max(dot(n, Hm), 0.0), 180.0);
  spm = spm * (0.5 + 0.6 * vnoise(pw * 1.1 + vec2f(-t * 0.6, t * 0.4)));
  c += vec3f(0.9, 1.0, 1.15) * spm * night * 0.9;

  // starlight freckles on calm night water
  let sh = hash21(floor(pw * 0.35 + vec2f(t * 0.15, 0.0)));
  c += vec3f(0.5, 0.55, 0.7) * step(0.995, sh) * night * (1.0 - w01) * (0.4 + 0.4 * sin(t * 2.0 + sh * 40.0)) * smoothstep(0.3, -0.2, h0);

  // whitecaps grow with wind
  let cap = smoothstep(0.62 - w01 * 0.25, 1.05, h0) * (0.4 + 0.6 * vnoise(pw * 0.5 + vec2f(t * 0.6, 0.0)));
  c = mix(c, mix(vec3f(0.62, 0.66, 0.68), vec3f(0.25, 0.28, 0.33), night), cap * (0.25 + 0.55 * w01));

  // wind streaks — elongated noise aligned with the wind
  let perp = vec2f(-wdir.y, wdir.x);
  let streak = vnoise(vec2f(dot(pw, perp) * 0.55, dot(pw, wdir) * 0.045 - t * 0.5));
  c *= 0.94 + 0.12 * streak * (0.3 + 0.7 * w01);

  // drifting cloud shadows, day only
  let cs = fbm(pw * 0.006 + wdir * t * 0.012, 3);
  c *= mix(1.0, 0.82 + 0.28 * cs, day);

  // after dusk the lighthouse gilds the crests — the beam walks the water
  let bv = pw - vec2f(uni(5), uni(6));
  let blen = length(bv);
  var bAng = atan2(bv.y, bv.x) - uni(2);
  bAng = atan2(sin(bAng), cos(bAng));
  let wedge = pow(max(cos(bAng), 0.0), 240.0);
  let reach = smoothstep(20.0, 60.0, blen) * exp(-blen * 0.006);
  c += vec3f(1.5, 1.1, 0.6) * wedge * reach * night * (0.5 + 0.9 * clamp(h0 + 0.6, 0.0, 1.3));

  return vec4f(c, 1.0);
}

fn visual_tr_whirl(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 0.97) { return vec4f(0.0); }
  let ang = atan2(uv.y, uv.x);
  let sang = ang + 4.2 * log(r + 0.13) + time * 0.9;
  let streak = pow(0.5 + 0.5 * sin(sang * 3.0), 2.0);
  // bowl darkening toward the drain
  var c = mix(vec3f(0.050, 0.115, 0.150), vec3f(0.008, 0.022, 0.032), smoothstep(0.75, 0.05, r));
  c *= 0.75 + 0.4 * streak;
  // sheared foam collar and inner filaments
  let foamN = vnoise(vec2f(sang * 2.0, r * 14.0 - time * 0.8));
  var foam = exp(-pow((r - 0.72) * 7.0, 2.0)) * (0.4 + 0.6 * foamN);
  foam += smoothstep(0.28, 0.05, r) * streak * 0.5 * foamN;
  c += vec3f(0.55, 0.60, 0.62) * foam;
  let a = smoothstep(0.95, 0.6, r) * 0.92;
  return vec4f(c, a);
}

fn visual_tr_rock(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [seed, 0, surgePhaseOffset, 0]
  let r = length(uv);
  if (r > 0.98) { return vec4f(0.0); }
  let ca = uv / max(r, 0.001);
  let seed = p.x;
  var rockR = 0.46 + 0.16 * (vnoise(ca * 2.1 + vec2f(seed * 9.0, seed * 4.0)) - 0.5) * 2.0;
  rockR += 0.07 * (vnoise(ca * 5.0 + vec2f(seed * 3.0, seed * 7.0)) - 0.5) * 2.0;

  var c = vec3f(0.0);
  var a = 0.0;
  let surge = sin(time * 1.25 + p.z * 6.28);

  if (r < rockR) {
    // craggy top-lit basalt; height falls toward the waterline
    let hgt = clamp((rockR - r) / rockR, 0.0, 1.0);
    let tex = fbm(uv * 9.0 + vec2f(seed * 20.0, 0.0), 4);
    c = mix(vec3f(0.055, 0.052, 0.050), vec3f(0.16, 0.145, 0.125), hgt * (0.5 + 0.5 * tex));
    // warm dusk grazing light from the west
    let sun2 = vec2f(cos(uni(1)), sin(uni(1)));
    let grad = vnoise(uv * 7.0 + vec2f(seed * 11.0, 3.0)) - vnoise(uv * 7.0 + sun2 * 0.25 + vec2f(seed * 11.0, 3.0));
    c += vec3f(0.55, 0.30, 0.16) * clamp(grad * 3.0, 0.0, 0.35) * hgt * (0.25 + smoothstep(0.35, 0.04, abs(uni(0))));
    // wet dark band at the waterline
    c *= mix(0.35, 1.0, smoothstep(0.02, 0.14, rockR - r));
    a = 1.0;
  } else {
    // breaking surf collar — swells on a slow pulse, textured foam
    let d = r - rockR;
    let foamN = vnoise(uv * 11.0 + vec2f(time * 0.7, seed * 8.0));
    var foam = exp(-d * d * 160.0) * (0.55 + 0.35 * surge) * (0.45 + 0.55 * foamN);
    foam += exp(-pow((d - 0.10 - 0.03 * surge) * 16.0, 2.0)) * 0.4 * foamN;
    c = vec3f(0.72, 0.75, 0.76) * foam * 1.25;
    a = clamp(foam * 1.15, 0.0, 1.0);
  }
  c *= 0.45 + 0.65 * smoothstep(-0.10, 0.25, uni(0));
  return vec4f(c, a);
}

fn visual_tr_squall(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [windX, windY, intensity, 0]
  let r = length(uv);
  if (r > 0.98) { return vec4f(0.0); }
  var wdir = vec2f(p.x, p.y);
  if (length(wdir) < 0.1) { wdir = vec2f(1.0, 0.0); }
  wdir = normalize(wdir);
  let perp = vec2f(-wdir.y, wdir.x);
  let edge = smoothstep(0.95, 0.45, r);
  // grey rain veil
  var c = vec3f(0.115, 0.130, 0.145);
  var a = 0.38 * edge * p.z;
  // rain streaks driven along the wind
  let streak = vnoise(vec2f(dot(uv, perp) * 26.0, dot(uv, wdir) * 2.2 - time * 2.2));
  c += vec3f(0.10, 0.11, 0.12) * pow(streak, 3.0) * 2.0;
  // agitated water sheen beneath
  let churn = vnoise(uv * 14.0 + vec2f(time * 1.3, 0.0));
  c += vec3f(0.16, 0.18, 0.19) * churn * 0.35;
  a = clamp(a + pow(streak, 3.0) * 0.25 * edge, 0.0, 0.75);
  c *= 0.45 + 0.7 * smoothstep(-0.08, 0.25, uni(0));
  return vec4f(c, a);
}

fn visual_tr_light(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [beamAngle, deliverGlow, 0, 0] — islet with tower, rotating beam, and a plank dock (south)
  let r = length(uv);
  var c = vec3f(0.0);
  var a = 0.0;

  // rotating beam wedge over the water (HDR, soft)
  let ang = atan2(uv.y, uv.x);
  var dAng = ang - p.x;
  dAng = atan2(sin(dAng), cos(dAng));
  let wedge = pow(max(cos(dAng), 0.0), 48.0);
  let reach = smoothstep(0.10, 0.30, r) * exp(-r * (1.6 - 0.85 * clamp(uni(3), 0.0, 1.0)));
  let boxFade = smoothstep(1.0, 0.68, max(abs(uv.x), abs(uv.y)));
  c += vec3f(2.0, 1.5, 0.85) * wedge * reach * boxFade * (1.1 + p.y * 1.4 + clamp(uni(3), 0.0, 1.0) * 1.8);
  a = max(a, clamp(wedge * reach * boxFade * 2.0, 0.0, 0.55));

  // islet
  let rockR = 0.40 + 0.10 * (vnoise(uv / max(r, 0.001) * 2.4 + vec2f(4.0, 8.0)) - 0.5) * 2.0;
  if (r < rockR * 0.42) {
    let hgt = clamp((rockR * 0.42 - r) / (rockR * 0.42), 0.0, 1.0);
    let tex = fbm(uv * 8.0 + vec2f(13.0, 5.0), 4);
    c = mix(vec3f(0.06, 0.055, 0.05), vec3f(0.17, 0.15, 0.13), hgt * (0.5 + 0.5 * tex));
    c *= mix(0.4, 1.0, smoothstep(0.01, 0.08, rockR * 0.42 - r));
    a = 1.0;
  } else if (r < rockR * 0.42 + 0.10) {
    let d = r - rockR * 0.42;
    let foamN = vnoise(uv * 12.0 + vec2f(time * 0.7, 2.0));
    let foam = exp(-d * d * 220.0) * (0.6 + 0.3 * sin(time * 1.25)) * (0.5 + 0.5 * foamN);
    c = max(c, vec3f(0.72, 0.75, 0.76) * foam * 1.2);
    a = max(a, clamp(foam, 0.0, 1.0));
  }
  // dock: weathered planks running south
  let dq = uv - vec2f(0.02, 0.30);
  let dockD = sdBox(dq, vec2f(0.055, 0.22));
  if (dockD < 0.0) {
    let plank = 0.8 + 0.2 * sin(dq.y * 90.0);
    c = vec3f(0.30, 0.21, 0.13) * plank * (0.8 + 0.2 * vnoise(dq * 40.0));
    a = 1.0;
  }
  // tower: white drum, red lantern, warm halo
  if (r < 0.085) {
    let ring = smoothstep(0.085, 0.055, r);
    c = mix(vec3f(0.75, 0.72, 0.68), vec3f(0.9, 0.88, 0.84), ring);
    a = 1.0;
  }
  c += vec3f(3.0, 1.6, 0.6) * exp(-r * r * 300.0) * (1.0 + p.y * 2.0 + clamp(uni(3), 0.0, 1.0) * 1.5);
  return vec4f(c, a);
}

fn visual_tr_raft(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [seed, 0, 0, hidden] — a lantern lashed to a small raft
  if (p.w > 0.5) { return vec4f(0.0); }
  let r = length(uv);
  var c = vec3f(0.0);
  var a = 0.0;
  // expanding ripple rings (slow)
  let rip = sin(r * 22.0 - time * 2.2 + p.x * 9.0) * exp(-r * 2.6);
  c += vec3f(0.10, 0.12, 0.13) * max(rip, 0.0) * 0.8;
  a = max(a, max(rip, 0.0) * 0.35);
  // raft planks
  let rq = rotate(uv, p.x * 6.0);
  if (sdBox(rq, vec2f(0.16, 0.11)) < 0.0) {
    c = vec3f(0.24, 0.17, 0.11) * (0.8 + 0.2 * sin(rq.y * 70.0));
    a = 1.0;
  }
  // warm lantern — gentle breathing, HDR for bloom
  let breathe = 0.85 + 0.15 * sin(time * 1.6 + p.x * 12.0);
  c += vec3f(2.6, 1.5, 0.55) * exp(-r * r * 60.0) * breathe;
  c += vec3f(1.2, 0.6, 0.2) * exp(-r * r * 9.0) * 0.5 * breathe;
  a = max(a, clamp(exp(-r * r * 20.0) * 1.3, 0.0, 1.0));
  return vec4f(c, a);
}

fn visual_tr_boat(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [heading, speed01, boomAngle, heel(-1..1)] — +x forward in boat frame
  let q = rotate(uv, -p.x);
  let spd = clamp(p.y, 0.0, 1.0);
  let sun2n = normalize(vec2f(cos(uni(1)), sin(uni(1))));
  let shD = rotate(-sun2n, -p.x) * 0.045;      // shadow cast away from the sun, in boat frame
  var c = vec3f(0.0);
  var a = 0.0;

  // ---- Kelvin wake ----
  if (q.x < 0.02 && spd > 0.04) {
    let wx = 0.02 - q.x;
    let wy = q.y;
    let slope = abs(wy) / max(wx, 0.002);
    let armD = abs(slope - 0.354) * wx;
    let arm = exp(-armD * armD * 800.0) * exp(-wx * 2.3);
    var trans = 0.0;
    if (slope < 0.354) {
      trans = (0.5 + 0.5 * sin(wx * (34.0 + 26.0 * (1.0 - spd)))) * exp(-wx * 2.8) * smoothstep(0.354, 0.12, slope);
    }
    let turb = exp(-wy * wy * 260.0) * exp(-wx * 3.0) * (0.55 + 0.45 * vnoise(vec2f(wx * 26.0 - time * 4.0 * spd, wy * 36.0)));
    let foam = (arm + turb * 0.95) * spd;
    c += vec3f(0.70, 0.76, 0.78) * foam * 1.25;
    c += vec3f(0.16, 0.22, 0.26) * trans * spd * 0.8;
    a = max(a, clamp(foam * 1.25 + trans * spd * 0.35, 0.0, 1.0) * 0.9);
  }

  // hull profile: pointed bow (+x), squared transom
  let hL = 0.34;
  let hW = 0.10;
  // ---- shadow on the water (hull + sail silhouette, offset from the sun) ----
  let sq = q - shD;
  let sxn = sq.x / hL;
  if (abs(sxn) < 1.0) {
    let wp = hW * sqrt(max(0.0, 1.0 - sxn * sxn)) * (1.0 - 0.45 * smoothstep(0.1, 1.0, sxn));
    if (abs(sq.y) < wp && sq.x > -hL * 0.94) {
      c = mix(c, vec3f(0.005, 0.012, 0.016), 0.55);
      a = max(a, 0.5);
    }
  }

  // ---- hull ----
  let hq = vec2f(q.x, q.y + p.w * 0.010);     // heel shifts the deck line
  let xn = hq.x / hL;
  if (abs(xn) < 1.0 && hq.x > -hL * 0.94) {
    let wProf = hW * sqrt(max(0.0, 1.0 - xn * xn)) * (1.0 - 0.45 * smoothstep(0.1, 1.0, xn));
    let dy = abs(hq.y);
    if (dy < wProf) {
      // teak deck, planked; brighter on the sunward rail (heel-aware)
      let plank = 0.85 + 0.15 * sin(hq.y * 260.0);
      var deck = vec3f(0.36, 0.26, 0.17) * plank * (0.85 + 0.15 * vnoise(hq * 80.0));
      let railLight = clamp(-hq.y * sign(p.w) * 10.0, -0.2, 0.35);
      deck *= 0.9 + railLight;
      // white gunwale
      let rail = smoothstep(wProf - 0.011, wProf - 0.004, dy);
      deck = mix(deck, vec3f(0.82, 0.80, 0.76), rail);
      // cabin house aft of the mast
      let cd = sdRoundedBox(hq - vec2f(-0.075, 0.0), vec2f(0.055, 0.032), 0.015);
      if (cd < 0.0) { deck = mix(vec3f(0.46, 0.35, 0.24), vec3f(0.55, 0.44, 0.30), 0.5 + 0.5 * sin(hq.x * 200.0)); }
      c = deck * (0.9 + 0.35 * clamp(dot(rotate(vec2f(1.0, 0.0), p.x), -sun2n), 0.0, 1.0));
      a = 1.0;
    }
    // bow spray
    if (xn > 0.55 && spd > 0.35) {
      let bq = hq - vec2f(hL, 0.0);
      let spray = exp(-dot(bq, bq) * 320.0) * spd * (0.5 + 0.5 * vnoise(hq * 60.0 + vec2f(time * 3.0, 0.0)));
      c += vec3f(0.75, 0.8, 0.82) * spray;
      a = max(a, clamp(spray, 0.0, 0.8));
    }
  }

  // ---- rig: mast, boom, canvas ----
  let mast = vec2f(0.075, 0.0);
  let boomAng = p.z;
  let tip = mast + vec2f(cos(3.14159 + boomAng), sin(3.14159 + boomAng)) * 0.27;  // boom sweeps aft
  // sail: curved panel from mast to boom tip, cambered to leeward
  let mid = (mast + tip) * 0.5 + vec2f(-(tip - mast).y, (tip - mast).x) * 0.16;
  let d1 = sdSegment(q, mast, mid);
  let d2 = sdSegment(q, mid, tip);
  let sailD = min(d1, d2);
  if (sailD < 0.020) {
    // cream dacron lit by the low sun
    let lit = 0.65 + 0.4 * clamp(dot(normalize(tip - mast), sun2n), -0.4, 1.0);
    c = vec3f(0.88, 0.84, 0.74) * lit;
    a = 1.0;
  }
  // boom shadow line on deck
  let bD = sdSegment(q, mast, tip);
  if (bD < 0.006) { c = mix(c, vec3f(0.06, 0.05, 0.04), 0.7); a = max(a, 0.9); }
  // mast head
  c += vec3f(0.9, 0.85, 0.75) * exp(-dot(q - mast, q - mast) * 2600.0);
  a = max(a, clamp(exp(-dot(q - mast, q - mast) * 2000.0), 0.0, 1.0));

  let nb = clamp(uni(3), 0.0, 1.0);
  c *= 1.0 - 0.45 * nb;
  let lq = q - vec2f(0.075, 0.0);
  let lant = exp(-dot(lq, lq) * 2200.0);
  c += vec3f(1.4, 0.9, 0.42) * lant * nb * 1.6;
  a = max(a, clamp(lant * nb, 0.0, 0.9));
  a *= smoothstep(1.0, 0.92, length(uv));
  return vec4f(c, a);
}

fn visual_tr_hud(uv: vec2f, sdf: f32, col: vec4f, time: f32, p: vec4f, behind: vec4f) -> vec4f {
  // p = [hull, cargo, windAngle, wind01] — quiet glass instruments, no chrome
  var c = vec3f(0.0);
  var a = 0.0;
  // wind rose: arrow rotated to where the wind blows
  let wq = rotate((uv - vec2f(-0.86, 0.0)) * vec2f(8.0, 3.6), -p.z);
  let tri = sdEquilateralTriangle(rotate(wq, 1.5708), 0.30);
  let ring = abs(length(wq) - 0.42);
  c += vec3f(0.75, 0.82, 0.88) * smoothstep(0.05, -0.02, tri) * (0.55 + 0.45 * p.w);
  c += vec3f(0.45, 0.55, 0.62) * smoothstep(0.03, 0.0, ring) * 0.5;
  a = max(a, smoothstep(0.05, -0.02, tri) * 0.85);
  a = max(a, smoothstep(0.03, 0.0, ring) * 0.4);
  // hull integrity: three small planks
  for (var i = 0; i < 3; i++) {
    let q = (uv - vec2f(-0.55 + f32(i) * 0.09, 0.0)) * vec2f(12.0, 5.0);
    let on = select(0.12, 1.0, f32(i) < p.x);
    let g = exp(-dot(q, q) * 2.0);
    c += vec3f(0.85, 0.55, 0.35) * g * on;
    a = max(a, g * 0.7);
  }
  // cargo lanterns aboard
  for (var i = 0; i < 4; i++) {
    let q = (uv - vec2f(0.30 + f32(i) * 0.09, 0.0)) * vec2f(12.0, 5.0);
    let on = select(0.10, 1.0, f32(i) < p.y);
    let g = exp(-dot(q, q) * 2.0);
    c += vec3f(1.6, 0.95, 0.35) * g * on;
    a = max(a, g * 0.75 * max(on, 0.25));
  }
  return vec4f(c, clamp(a, 0.0, 1.0) * 0.8);
}

fn visual_tr_windrose(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  let off = params.x;
  let wind01 = clamp(params.y, 0.0, 1.0);
  let drive01 = clamp(params.z, 0.0, 1.0);
  let flash = params.w >= 1.6;
  let heel01 = clamp(select(params.w, params.w - 2.0, flash), 0.0, 1.0);
  // dial backing + rim
  var col = vec3f(0.045, 0.06, 0.09);
  var a = 0.60 * smoothstep(1.0, 0.96, r);
  let rim = smoothstep(0.055, 0.0, abs(r - 0.93));
  col += vec3f(0.42, 0.52, 0.62) * rim;
  a = max(a, rim * 0.85);
  // boat heading is UP on this dial. y is down, so up = -y.
  let ang = atan2(uv.x, -uv.y);
  // the no-go cone — if the wind arrow sits in here, the sail is dead
  let cone = step(abs(ang), 0.42) * step(r, 0.90) * smoothstep(0.06, 0.22, r);
  col = mix(col, vec3f(0.52, 0.10, 0.10), cone * 0.6);
  a = max(a, cone * 0.5);
  // wind arrow: blows FROM its rim point toward the boat. rel bearing = -off.
  let b = -off;
  let u = vec2f(sin(b), -cos(b));                     // rim point direction
  let proj = dot(uv, u);
  let perp = abs(uv.x * u.y - uv.y * u.x);
  let inIrons = step(abs(atan2(sin(b), cos(b))), 0.46);
  var wcol = mix(vec3f(0.40, 0.78, 0.95), vec3f(1.0, 1.0, 1.0), wind01);
  wcol = mix(wcol, vec3f(1.0, 0.30, 0.22), inIrons);  // arrow burns red in the cone
  let shaft = step(perp, 0.045 + wind01 * 0.02) * step(0.34, proj) * step(proj, 0.86);
  let head = step(0.16, proj) * step(proj, 0.36) * step(perp, (0.36 - proj) * 0.62);
  let arrow = max(shaft, head);
  col = mix(col, wcol * (0.75 + 0.5 * wind01), arrow);
  a = max(a, arrow * 0.95);
  // the sloop: a small glyph, always pointing up
  let tri = step(-0.15, uv.y) * step(uv.y, 0.12) * step(abs(uv.x), (uv.y + 0.16) * 0.42);
  col = mix(col, vec3f(0.92, 0.90, 0.82), tri);
  a = max(a, tri * 0.95);
  // drive arc along the bottom rim — how much of the wind you're harvesting
  let bot = 3.14159 - abs(ang);
  let arcBand = step(0.74, r) * step(r, 0.88);
  let lit = arcBand * step(bot, 1.05 * drive01) * step(0.02, drive01);
  var dcol = mix(vec3f(0.85, 0.45, 0.12), vec3f(0.25, 0.85, 0.35), smoothstep(0.35, 0.75, drive01));
  dcol = mix(vec3f(0.75, 0.20, 0.12), dcol, smoothstep(0.05, 0.30, drive01));
  col = mix(col, dcol, lit);
  a = max(a, lit * 0.9);
  // heel bar, left side: fills upward; flashes when a broach is one breath away
  let bar = step(abs(uv.x + 0.60), 0.05) * step(0.5 - heel01 * 1.0, uv.y) * step(uv.y, 0.52);
  var hcol = mix(vec3f(0.9, 0.75, 0.25), vec3f(1.0, 0.25, 0.15), smoothstep(0.5, 0.9, heel01));
  if (flash) { hcol *= 0.55 + 0.45 * sin(time * 11.0); }
  col = mix(col, hcol, bar);
  a = max(a, bar * 0.9);
  return vec4f(col, a);
}

fn visual_tr_pearl(uv0: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  if (params.w > 0.5) { return vec4f(0.0); }
  let seed = params.x * 6.283;
  var uv = uv0;
  uv.y += sin(time * 1.1 + seed) * 0.07;
  let r = length(uv);
  if (r > 1.0) { return vec4f(0.0); }
  var col = vec3f(0.0);
  var a = 0.0;
  // sea-glow halo, breathing
  let halo = exp(-r * r * 3.0) * (0.55 + 0.2 * sin(time * 0.9 + seed)) * (1.0 + clamp(uni(3), 0.0, 1.0) * 1.3);
  col += vec3f(0.55, 0.78, 0.88) * halo * 0.55;
  a += halo * 0.5;
  // the pearl: lit sphere with mother-of-pearl sheen
  let d = uv / 0.34;
  let d2 = dot(d, d);
  if (d2 < 1.0) {
    let z = sqrt(1.0 - d2);
    let nrm = normalize(vec3f(d.x, d.y, z));
    let L = normalize(vec3f(-0.5, -0.6, 0.62));
    let dif = max(0.0, dot(nrm, L));
    let fres = pow(1.0 - z, 2.0);
    let hue = fres * 5.0 + seed + atan2(d.y, d.x) * 0.7;
    var pc = vec3f(0.86, 0.84, 0.86);
    pc += (0.5 + 0.5 * cos(vec3f(hue, hue + 2.09, hue + 4.19))) * 0.16;
    pc = pc * (0.4 + dif * 0.75);
    let spec = pow(max(0.0, dot(reflect(vec3f(0.0, 0.0, -1.0), nrm), L)), 60.0);
    pc += vec3f(1.0) * spec * 0.9;
    col = pc;
    a = max(a, smoothstep(1.0, 0.85, d2));
  }
  return vec4f(col, a);
}
